var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래서, 생명에 지장은 없는 건가?","JPN":"それで、命に別状はないのか？","ENG":"So, is he going to live?","TWN":"所以，沒有生命危險嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다니까. 피를 너무 많이 흘려서 기절한 거래.","JPN":"そうよ。血を流しすぎたせいで気絶したんだって。","ENG":"Yeah. He just fainted because he lost a lot of blood.","TWN":"是的，就是失血過多暈過去了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"수술은 잘 끝났어. 부상이 다 나을 때까지 안정만 잘 취하래.","JPN":"手術は無事に終わったから、怪我が治るまで安静にしていればいいらしいわ。","ENG":"The surgery went well. The doc wants you to rest until your wounds heal.","TWN":"手術結束了。在傷口痊癒之前要好好休息。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 확실히 정규군의 의료 수준은 다르더군.","JPN":"まぁ、正規軍の医療レベルはそこらのものとは確かに違ったな。","ENG":"The standard of medical care is on another level in the army, you know?","TWN":"嗯，正規軍的醫療水準確實不一樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"저 녀석, 매번 죽을 짓을 하는데도 용케 살아난다니까.","JPN":"あいつ、毎回命知らずなことをやるのに、なぜか生き延びるんだよな。","ENG":"Him again. He always somehow survives after putting himself at the brink of death.","TWN":"那傢伙，每次做了會死的事都能活下來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"휘말리는 우리 입장도 좀 생각해 주라고.","JPN":"それに巻き込まれる俺たちの身にもなってほしいぜ。","ENG":"Think about how that makes us look, all right?","TWN":"拜託你也想想捲入其中的我們的立場。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"맞아. 이번에는 정말 아찔했다고.","JPN":"まったくだ。今回は本当にヒヤッとしたぜ。","ENG":"Yeah. It was a close one this time.","TWN":"沒錯，這次真的很驚險。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후후, 행운의 여신도 가끔은 새침할 때가 있는 거지.","JPN":"ハハッ、幸運の女神もたまには意地悪になるってことさ。","ENG":"Ha ha, Lady Luck can be moody sometimes.","TWN":"哈哈，幸運女神也會有心情不好的時候。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"으억!","JPN":"うおっ！","ENG":"Gwuh!","TWN":"呃！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭘 웃어! 누군 죽은 줄 알고 심장 떨어질 뻔했는데!","JPN":"何がハハ、よ！　死んだと思って心臓止まるかと思ったのに！","ENG":"What are you laughing about? We were worried sick that you might not make it!","TWN":"你笑什麼！我還以為有人死了，心臟差點掉出來！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"때, 때려도 하필 다친 데를…….","JPN":"き、傷があるところを殴るなんて……","ENG":"Y-you just had to hit me where it hurts the most...","TWN":"為，為什麼偏偏打受傷的地方……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 미, 미안! 괜찮아? 많이 아파?","JPN":"え？　ご、ごめん！　大丈夫？　痛かった？？","ENG":"What? S-sorry! You okay? Does it hurt a lot?","TWN":"什麼？對，對不起！你沒事吧？很疼嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……괜찮아 보여서 다행이군.","JPN":"……大事に至らずなによりだ。","ENG":"...Good to see you back on your feet.","TWN":"……幸好看起來沒事。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"등대는 어떻습니까, 회장님.","JPN":"灯台はどうなりましたか、会長。","ENG":"Miss Shin, what happened to the Lighthouse?","TWN":"燈塔怎麼樣了，會長。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"펑 터져 버려서 수리는 불가능하겠어요. 새로 만드는 편이 더 빠르겠네요.","JPN":"爆発で完全に壊れてしまって、修理は無理ですね。新しく建て直した方が早いというか。","ENG":"It exploded beyond repair. It would be faster to construct a new one.","TWN":"爆炸了，修理是不可能的了。也許建個新的會更快。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"일말의 여지도 없이 시원하게 대답하시는군요.","JPN":"スパッと言い切りますね。","ENG":"You answered without any hesitation.","TWN":"回答得真是乾脆，一點轉圜的餘地都沒有呢。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};